1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — base premiums and processing fee
6	  it("empty item list yields premium of 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it.todo("quote for a single plain sword (steel, enchantment 3) yields 105 G");
14	  it.todo("quote for a single plain amulet yields 65 G");
15	  it.todo("quote for a single plain staff yields 85 G");
16	  it.todo("quote for a single plain potion yields 45 G");
17	
18	  // Components and blocks
19	  it.todo("quote for 2 runes yields 55 G (no block)");
20	  it.todo("quote for 3 runes applies block, yielding 65 G");
21	  it.todo("quote for 4 runes yields 105 G (no block, block requires exactly 3)");
22	  it.todo("quote for 7 runes yields 180 G (no block)");
23	  it.todo("quote for 2 runes + 1 moonstone yields 80 G (no block, different types)");
24	  it.todo("quote for 3 runes + 3 moonstones applies two blocks, yielding 125 G");
25	
26	  // Item-specific modifiers
27	  it.todo("cursed sword adds 50% surcharge on the item's base premium");
28	  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
29	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
30	  it.todo("cursed sword with enchantment 5 stacks both surcharges");
31	
32	  // Policy-wide modifiers
33	  it.todo("customer with exactly 2 years applies 20% loyalty discount");
34	  it.todo("first insurance adds 10% initial assessment surcharge");
35	  it.todo("follow-up contract applies 15% discount on contracts after the first");
36	
37	  // Multi-item modifier scope
38	  it.todo("cursed surcharge applies only to the cursed item, not to whole policy");
39	
40	  // Rounding
41	  it.todo("premium is rounded up to whole G (MHPCO's favor)");
42	
43	  // Integration examples
44	  it.todo("newcomer with cursed sword yields 165 G");
45	  it.todo("long-standing customer's second contract with cursed enchanted sword yields 160 G");
46	
47	  // Claim — basic processing
48	  it.todo("claim on a regular sword with 500 G damage yields payout 400 G after deductible");
49	  it.todo("claim on a rune with 200 G damage yields payout 100 G after deductible");
50	  it.todo("claim on enchantment-9 sword (steel) with 1000 G damage yields payout 400 G");
51	  it.todo("claim on a dragon-material sword with 800 G damage yields full payout 700 G");
52	  it.todo("dragon-material sword with enchantment 9 and 1000 G damage yields payout 400 G");
53	
54	  // Deductible per damage event
55	  it.todo("multiple damaged items each incur their own deductible");
56	
57	  // Cap
58	  it.todo("payout is capped at twice the insurance sum across successive claims");
59	  it.todo("claim references unknown item rejects the claim");
60	
61	  // CLI errors
62	  it.todo("quote with unknown item type rejects the quote");
63	  it.todo("claim with negative damage amount is rejected");
64	});
